// U8g2 full buffer graphics mode for GP1294, software SPI
// Signature: (clock, data, cs, dc, reset)
// GP1294AI does not use DC -> U8X8_PIN_NONE
U8G2_GP1294AI_256X48_F_4W_SW_SPI u8g2(U8G2_R0, /* clock=*/ PIN_DISP_CLK,
                                                /* data=*/  PIN_DISP_MOSI,
                                                /* cs=*/    PIN_DISP_CS,
                                                /* dc=*/    U8X8_PIN_NONE,
                                                /* reset=*/ PIN_DISP_RST);

